def assess(record: dict) -> str:
    required = {"case_id", "lint", "matrix", "supported", "tests", "types"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (record["lint"] and record["types"] and record["tests"]) else "FAIL_CI_GATE"

valid = {'case_id': 'CASO-PIU-044-1A', 'lint': True, 'types': True, 'tests': True, 'matrix': {'3.12', '3.11'}, 'supported': {'3.12', '3.11'}}
invalid = {'case_id': 'CASO-PIU-044-1A', 'lint': True, 'types': False, 'tests': True, 'matrix': {'3.12', '3.10'}, 'supported': {'3.12', '3.11'}}
incomplete = dict(valid)
incomplete.pop("supported")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

